#!/usr/bin/env python3
"""DOI -> OA-LOCATION RESOLVER.  Resolution ONLY: it never fetches a document.

Every candidate DOI we hold carries no URL.  This walks OpenAlex and Unpaywall for each one, records
EVERY location either backend proposes as a DocumentCandidate on the durable ledger (an OBSERVATION:
locator, host, version hint, license -- never a conclusion), and consolidates them into
    outputs/acquisition_campaign/resolved_locations.json

THE ONE RULE.  A throttle is a fact about OUR REQUEST RATE.  A 403 is a fact about ENTITLEMENT.
Neither is ever allowed to become "no OA copy exists".  A DOI is written down as NO_OA_LOCATION_KNOWN
only when BOTH backends ANSWERED (200 or 404 -- a 404 is their index answering) and neither named a
location.  Anything else stays retriable, forever, and says so.

Resumable: one checkpoint line per DOI, appended before the next DOI starts.  A restart re-reads the
checkpoint and skips what is already terminal; retriable outcomes are re-attempted (up to MAX_PASSES).
It also RE-SCANS the input directory on every pass, so candidate files another wheel drops in later
(citation-graph sets, CORE/OpenAIRE leads) get resolved without a restart.
"""
from __future__ import annotations

import json
import os
import sys
import time
import urllib.parse
from pathlib import Path

CAMPAIGN = Path(__file__).resolve().parent
ROOT = CAMPAIGN.parent.parent                      # .../flywheel
sys.path.insert(0, str(ROOT))
sys.path.insert(0, str(ROOT / 'scripts'))

import acquisition                                  # noqa: E402
from acquisition import Acquirer, open_ledger       # noqa: E402
from event_ledger import ForbiddenLabel             # noqa: E402

MAILTO = os.environ.get('POLARIS_MAILTO', 'aldrin.or@c-polarbiotech.com')
acquisition.SPACING_S = float(os.environ.get('POLARIS_SPACING', '1.2'))   # >= 1.1s per host

OUT_JSON   = CAMPAIGN / 'resolved_locations.json'
CHECKPOINT = CAMPAIGN / 'resolver_checkpoint.jsonl'
STATS      = CAMPAIGN / 'resolve_stats.json'

# Inputs: every json in the campaign dir that carries DOI-bearing records, re-globbed each pass.
SKIP_FILES = {'resolved_locations.json', 'resolver_checkpoint.jsonl', 'resolve_stats.json',
              '_known_dois.json', 'direct_oa_queue.json'}

# transport outcome -> resolution outcome
TERMINAL = {'RESOLVED', 'NO_OA_LOCATION_KNOWN', 'AUTH_FAILED', 'ACCESS_DENIED'}
RETRIABLE = {'THROTTLED', 'TRANSPORT_ERROR'}
MAX_PASSES = 3
IDLE_POLLS = 20          # after the queue drains, poll the input dir this many times (60s apart)


# -- input harvesting ------------------------------------------------------------------------------
def _walk(node, out):
    """Any dict anywhere in any campaign JSON that carries a 'doi' is a candidate work."""
    if isinstance(node, dict):
        doi = node.get('doi')
        if isinstance(doi, str) and doi.strip():
            out.append(node)
            return
        for v in node.values():
            _walk(v, out)
    elif isinstance(node, list):
        for v in node:
            _walk(v, out)


def norm_doi(d: str) -> str:
    d = (d or '').strip()
    for p in ('https://doi.org/', 'http://doi.org/', 'doi:', 'DOI:'):
        if d.lower().startswith(p.lower()):
            d = d[len(p):]
    return d.strip().lower()


def load_candidates() -> dict:
    """-> {doi: record}.  First file to name a DOI wins its metadata; later ones only fill blanks."""
    cands: dict[str, dict] = {}
    for f in sorted(CAMPAIGN.glob('*.json')):
        if f.name in SKIP_FILES:
            continue
        try:
            data = json.loads(f.read_text())
        except Exception:
            continue
        rows: list = []
        _walk(data, rows)
        for r in rows:
            doi = norm_doi(r.get('doi', ''))
            if not doi or '/' not in doi:
                continue
            cur = cands.setdefault(doi, {'doi': doi, 'sources': []})
            for k in ('title', 'venue', 'year', 'cell_served'):
                if not cur.get(k) and r.get(k):
                    cur[k] = r[k]
            if f.name not in cur['sources']:
                cur['sources'].append(f.name)
    return cands


# -- location extraction ---------------------------------------------------------------------------
def _host_of(url: str) -> str:
    try:
        return urllib.parse.urlparse(url).netloc or ''
    except Exception:
        return ''


def _add(locs: dict, url, *, host_type='', version='', license_='', source=''):
    if not url or not isinstance(url, str):
        return
    if url in locs:
        return
    locs[url] = {'url': url, 'host': _host_of(url), 'host_type': str(host_type or ''),
                 'version_hint': str(version or ''), 'license': str(license_ or ''),
                 'source': source}


def openalex_locations(work: dict) -> dict:
    """Every location OpenAlex names -- best_oa_location, primary_location, locations[]."""
    locs: dict = {}
    seen = []
    for key in ('best_oa_location', 'primary_location'):
        if isinstance(work.get(key), dict):
            seen.append((work[key], f'openalex:{key}'))
    for loc in (work.get('locations') or []):
        if isinstance(loc, dict):
            seen.append((loc, 'openalex:locations'))
    for loc, src in seen:
        src_obj = loc.get('source') or {}
        ht = (src_obj.get('type') if isinstance(src_obj, dict) else '') or ''
        _add(locs, loc.get('pdf_url'), host_type=ht, version=loc.get('version'),
             license_=loc.get('license'), source=src + ':pdf')
        _add(locs, loc.get('landing_page_url'), host_type=ht, version=loc.get('version'),
             license_=loc.get('license'), source=src + ':landing')
    return locs


def unpaywall_locations(up: dict) -> dict:
    locs: dict = {}
    for loc in (up.get('oa_locations') or []):
        if not isinstance(loc, dict):
            continue
        _add(locs, loc.get('url_for_pdf'), host_type=loc.get('host_type'), version=loc.get('version'),
             license_=loc.get('license'), source='unpaywall:pdf')
        _add(locs, loc.get('url'), host_type=loc.get('host_type'), version=loc.get('version'),
             license_=loc.get('license'), source='unpaywall:url')
    return locs


# -- ledger ----------------------------------------------------------------------------------------
def record(acq: Acquirer, unit: str, adapter: str, loc: dict, rid: str) -> str:
    """CANDIDATE_IDENTIFIED.  Observations only; the reducer concludes.  If the ledger's conclusion
    guard refuses one of the world's strings, we record the bare locator rather than lose the lead."""
    obs = dict(resolver_request_id=rid,
               host=loc['host'], host_type=loc['host_type'],
               oa_version=loc['version_hint'],            # observation only -- never a version decision
               license_observation=loc['license'],
               proposed_by=loc['source'])
    try:
        return acq.candidate(unit, adapter, loc['url'], **obs)
    except ForbiddenLabel:
        return acq.candidate(unit, adapter, loc['url'], resolver_request_id=rid, host=loc['host'],
                             guard_stripped_observation=True)


# -- one DOI ---------------------------------------------------------------------------------------
def resolve_one(acq: Acquirer, rec: dict, cooldown: dict) -> dict:
    doi = rec['doi']
    unit = doi
    acq.plan_route(unit, ['openalex', 'unpaywall'], doi=doi,
                   requested_title=str(rec.get('title') or ''),
                   requested_venue=str(rec.get('venue') or ''),
                   requested_year=rec.get('year'))

    locs: dict = {}
    outcomes = {}

    # 1. OpenAlex -- ALL locations
    oa_url = (f'https://api.openalex.org/works/doi:{urllib.parse.quote(doi, safe="")}'
              f'?mailto={urllib.parse.quote(MAILTO)}')
    r, body = acq.get_json(unit, 'openalex', oa_url, tries=4, timeout=30)
    outcomes['openalex'] = {'outcome': r.outcome, 'http_status': r.http_status}
    if r.ok and isinstance(body, dict):
        found = openalex_locations(body)
        for loc in found.values():
            record(acq, unit, 'openalex', loc, r.request_id)
        locs.update(found)
    if r.outcome == 'THROTTLED':
        cooldown['n'] += 1

    # 2. Unpaywall -- oa_locations
    up_url = (f'https://api.unpaywall.org/v2/{urllib.parse.quote(doi, safe="/")}'
              f'?email={urllib.parse.quote(MAILTO)}')
    r2, body2 = acq.get_json(unit, 'unpaywall', up_url, tries=4, timeout=30)
    outcomes['unpaywall'] = {'outcome': r2.outcome, 'http_status': r2.http_status}
    if r2.ok and isinstance(body2, dict):
        found = unpaywall_locations(body2)
        for u, loc in found.items():
            record(acq, unit, 'unpaywall', loc, r2.request_id)
            if u not in locs:
                locs[u] = loc
    if r2.outcome == 'THROTTLED':
        cooldown['n'] += 1

    # 3. THE HONEST OUTCOME.  Order matters: a throttle can never be outranked by an absence.
    o1, o2 = outcomes['openalex']['outcome'], outcomes['unpaywall']['outcome']
    codes = [outcomes['openalex']['http_status'], outcomes['unpaywall']['http_status']]
    if locs:
        res = 'RESOLVED'
    elif 'THROTTLED' in (o1, o2):
        res = 'THROTTLED'                         # a fact about our request rate. RETRIABLE.
    elif 'BLOCKED' in (o1, o2):
        res = 'AUTH_FAILED' if 401 in codes else 'ACCESS_DENIED'
    elif 'TRANSPORT_ERROR' in (o1, o2):
        res = 'TRANSPORT_ERROR'                  # we never got an answer. RETRIABLE.
    else:
        # both backends ANSWERED (200 and/or 404) and neither named a location.
        res = 'NO_OA_LOCATION_KNOWN'

    return {'doi': doi, 'title': rec.get('title', ''), 'venue': rec.get('venue', ''),
            'year': rec.get('year'), 'cell_served': rec.get('cell_served', ''),
            'from_files': rec.get('sources', []),
            'resolution': res, 'backends': outcomes,
            'locations': list(locs.values()), 'n_locations': len(locs),
            'resolved_at': time.time()}


# -- checkpoint ------------------------------------------------------------------------------------
def load_checkpoint() -> dict:
    done: dict = {}
    if CHECKPOINT.exists():
        for line in CHECKPOINT.read_text().splitlines():
            line = line.strip()
            if not line:
                continue
            try:
                d = json.loads(line)
            except Exception:
                continue
            if d.get('doi'):
                done[d['doi']] = d          # last write for a DOI wins
    return done


def write_out(done: dict, attempts: dict) -> None:
    rows = sorted(done.values(), key=lambda r: (r['resolution'] != 'RESOLVED', r['doi']))
    hist: dict = {}
    for r in rows:
        hist[r['resolution']] = hist.get(r['resolution'], 0) + 1
    payload = {'generated': time.time(), 'resolver': 'resolve_locations.py',
               'backends': ['openalex', 'unpaywall'], 'mailto': MAILTO,
               'note': ('locations are OBSERVATIONS proposed by a backend, not conclusions about '
                        'what the bytes are. THROTTLED / TRANSPORT_ERROR are facts about our request '
                        'rate and are RETRIABLE -- they are NOT absence of an OA copy.'),
               'counts': {'works': len(rows), 'by_resolution': hist,
                          'total_locations': sum(r['n_locations'] for r in rows)},
               'queue': rows}
    tmp = OUT_JSON.with_suffix('.tmp')
    tmp.write_text(json.dumps(payload, indent=1))
    tmp.replace(OUT_JSON)
    STATS.write_text(json.dumps({'ts': time.time(), 'by_resolution': hist,
                                 'total_locations': payload['counts']['total_locations'],
                                 'attempts': len(attempts)}, indent=1))


# -- main ------------------------------------------------------------------------------------------
def main() -> None:
    ledger = open_ledger()
    acq = Acquirer('resolve_locations', ledger=ledger)
    done = load_checkpoint()
    attempts: dict = {d: 1 for d in done}
    cooldown = {'n': 0}
    print(f'[start] {time.strftime("%H:%M:%S")} checkpoint carried {len(done)} DOIs', flush=True)

    idle = 0
    ck = open(CHECKPOINT, 'a')
    while True:
        cands = load_candidates()
        todo = [d for d in cands
                if (d not in done
                    or (done[d]['resolution'] not in TERMINAL
                        and attempts.get(d, 0) < MAX_PASSES))]
        if not todo:
            write_out(done, attempts)
            idle += 1
            if idle > IDLE_POLLS:
                print(f'[done] {len(done)} DOIs resolved; input dir idle. exiting.', flush=True)
                break
            time.sleep(60)
            continue
        idle = 0
        print(f'[pass] {len(cands)} candidates known, {len(todo)} to work', flush=True)

        for i, doi in enumerate(todo, 1):
            attempts[doi] = attempts.get(doi, 0) + 1
            before = cooldown['n']
            try:
                row = resolve_one(acq, cands[doi], cooldown)
            except Exception as e:                 # a crash is not an absence either
                row = {'doi': doi, 'title': cands[doi].get('title', ''),
                       'venue': cands[doi].get('venue', ''), 'year': cands[doi].get('year'),
                       'cell_served': cands[doi].get('cell_served', ''),
                       'from_files': cands[doi].get('sources', []),
                       'resolution': 'TRANSPORT_ERROR', 'backends': {},
                       'error_class': type(e).__name__, 'locations': [], 'n_locations': 0,
                       'resolved_at': time.time()}
            done[doi] = row
            ck.write(json.dumps(row) + '\n')
            ck.flush()
            os.fsync(ck.fileno())

            if i % 10 == 0 or i == len(todo):
                write_out(done, attempts)
                h: dict = {}
                for r in done.values():
                    h[r['resolution']] = h.get(r['resolution'], 0) + 1
                print(f'[{time.strftime("%H:%M:%S")}] {i}/{len(todo)} this pass | '
                      f'{len(done)}/{len(cands)} total | {h} | spacing={acquisition.SPACING_S:.1f}s',
                      flush=True)

            # THEY throttled US: back off the whole run, not just this request.
            if cooldown['n'] > before:
                acquisition.SPACING_S = min(acquisition.SPACING_S * 1.5, 20.0)
                print(f'[throttle] backing off -> spacing {acquisition.SPACING_S:.1f}s, '
                      f'sleeping 60s (this is our rate, NOT an absence)', flush=True)
                time.sleep(60)
    ck.close()
    write_out(done, attempts)


if __name__ == '__main__':
    main()

